#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-11

set -euo pipefail

# prune-playgrounds-report.sh — open or update the playground-drift tracking issue.
#
# Called by .github/workflows/prune-playgrounds.yml on the monthly schedule when
# the read-only scan finds prunable dirs. Deduplicates by a fixed title marker:
# comments on the existing open issue if present, else creates a new one. Never
# mutates files or branches — its only side effect is a GitHub issue.
#
# Env:
#   COUNT     number of prunable dirs (from the scan step, required)
#   GH_TOKEN  token with issues:write (provided by the workflow)

COUNT="${COUNT:-0}"
TITLE="Playground graveyard drift: prunable dirs detected"
APPLY_CMD='gh workflow run prune-playgrounds.yml -f apply=true'

body="$(cat <<EOF
The monthly drift scan found **${COUNT}** prunable playground dir(s) on \`main\`
— \`docs/<type>--<slug>/\` dirs whose branch is already merged + deleted from
origin and older than 30 days.

These are safe to move to the \`playgrounds-archive\` orphan branch. To prune
(archives + opens a removal PR for review — never a direct push to main):

\`\`\`bash
${APPLY_CMD}
\`\`\`

_Auto-filed by the \`Prune Playgrounds\` workflow. Re-runs monthly; this issue is
updated in place rather than duplicated._
EOF
)"

# Find an existing open issue with the marker title (exact-ish match).
existing="$(gh issue list --state open --search "${TITLE} in:title" \
  --json number,title --jq "map(select(.title == \"${TITLE}\")) | .[0].number // empty")"

if [ -n "${existing}" ]; then
  echo "Updating existing drift issue #${existing}"
  gh issue comment "${existing}" --body "${body}"
else
  echo "Creating new drift issue"
  gh issue create --label chore --title "${TITLE}" --body "${body}"
fi
